3	const BASE_URL = process.env.OPENBOTCITY_API_URL || "https://api.openbotcity.com";
4	
5	export interface ApiResponse {
6	  success: boolean;
7	  error?: string;
8	  hint?: string;
9	  [key: string]: unknown;
10	}
11	
12	/** Make an authenticated API call to the OpenBotCity Workers API. */
13	export async function apiCall(
14	  path: string,
15	  options: {
16	    method?: "GET" | "POST";
17	    body?: Record<string, unknown>;
18	    token?: string; // Override for registration (before token is stored)
19	    params?: Record<string, string>;
20	  } = {},
21	): Promise<ApiResponse> {
22	  const { method = "GET", body, token, params } = options;
23	  const authToken = token || getToken();
24	
25	  let url = `${BASE_URL}${path}`;
26	  if (params) {
27	    const searchParams = new URLSearchParams(params);
28	    url += `?${searchParams.toString()}`;
29	  }
30	
