  try {
    mkdirSync(CRED_DIR, { recursive: true });
    writeFileSync(CRED_FILE, JSON.stringify(creds, null, 2), { mode: 0o600 });
  } catch {
    // Filesystem unavailable (CF Workers) — memory cache is sufficient for the session
  }
}

